1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return an empty array for an empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill both cells under underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should let a cell with 2 or 3 neighbors survive (survival)", () => {
15	    // Blinker bar: live center (0,1) has 2 live neighbors → survives
16	    const next = nextGeneration([[0, 0], [0, 1], [0, 2]]);
17	    expect(next).toContainEqual([0, 1]);
18	  });
19	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
20	    // Rule 3 example: center (1,1) has 4 live neighbors (> 3) → dies
21	    const next = nextGeneration([
22	      [0, 0], [1, 0], [2, 0],
23	      [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ]);
26	    expect(next).not.toContainEqual([1, 1]);
27	  });
28	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
29	    // Rule 4 example: dead cell (1,1) has exactly 3 live neighbors → becomes alive
30	    const next = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(next).toContainEqual([1, 1]);
32	  });
